import psycopg2
from psycopg2 import sql
from typing import Optional, Dict, Any

def search_users(username: Optional[str] = None, email: Optional[str] = None, 
                 role: Optional[str] = None, status: Optional[str] = None) -> list:
    """
    Search users in PostgreSQL database based on multiple filter criteria.
    
    Args:
        username: Filter by username (partial match)
        email: Filter by email (partial match)
        role: Filter by role (admin/user/guest)
        status: Filter by account status (active/suspended)
    
    Returns:
        List of user profile dictionaries
    """
    try:
        # Database connection parameters
        conn_params = {
            'host': 'localhost',
            'database': 'your_database',
            'user': 'your_username',
            'password': 'your_password',
            'port': '5432'
        }
        
        with psycopg2.connect(**conn_params) as conn:
            with conn.cursor() as cursor:
                # Build dynamic query
                query_parts = []
                params = []
                
                if username is not None:
                    query_parts.append("username ILIKE %s")
                    params.append(f"%{username}%")
                    
                if email is not None:
                    query_parts.append("email ILIKE %s")
                    params.append(f"%{email}%")
                    
                if role is not None:
                    query_parts.append("role = %s")
                    params.append(role)
                    
                if status is not None:
                    query_parts.append("status = %s")
                    params.append(status)
                
                # Construct final query
                if query_parts:
                    query = "SELECT * FROM users WHERE " + " AND ".join(query_parts)
                else:
                    query = "SELECT * FROM users"
                
                cursor.execute(query, params)
                columns = [desc[0] for desc in cursor.description]
                results = cursor.fetchall()
                
                # Convert to list of dictionaries
                return [dict(zip(columns, row)) for row in results]
                
    except psycopg2.Error as e:
        raise Exception(f"Database error: {str(e)}")
    except Exception as e:
        raise Exception(f"Error: {str(e)}")